package rt.bindings.corba.org.apache.cxf.binding.corba.types;

public class CorbaAnyHandler extends CorbaObjectHandler { private Any value ; private CorbaObjectHandler containedType ; private CorbaTypeMap typeMap ; public CorbaAnyHandler ( QName anyName , QName anyIdlType , TypeCode anyTC , Object anyType ) { super ( anyName , anyIdlType , anyTC , anyType ) ; value = null ; } public Any getValue ( ) { return value ; } public void setAnyContainedType ( CorbaObjectHandler obj ) { containedType = obj ; } public CorbaObjectHandler getAnyContainedType ( ) { return containedType ; } public void clear ( ) { value = null ; } public void setTypeMap ( CorbaTypeMap tm ) { typeMap = tm ; } public CorbaTypeMap getTypeMap ( ) { return typeMap ; } public void setValue ( Any v ) throws CorbaBindingException { value = v ; } }